import numpy as np

class PolarizationQubit:
    """
    A class representing a polarization qubit state.
    """

    def __init__(self, alpha: complex, beta: complex):
        """
        Initialize a polarization state |psi> = alpha|H> + beta|V>.
        Automatically normalizes the state.
        """
        norm = np.sqrt(np.abs(alpha)**2 + np.abs(beta)**2)
        self.state = np.array([alpha/norm, beta/norm], dtype=complex)

    @classmethod
    def H(cls):
        """Create horizontal polarization |H>"""
        return cls(1, 0)

    @classmethod
    def V(cls):
        """Create vertical polarization |V>"""
        return cls(0, 1)

    @classmethod
    def D(cls):
        """Create diagonal polarization |D> = (|H> + |V>)/sqrt(2)"""
        return cls(1, 1)

    @classmethod
    def A(cls):
        """Create anti-diagonal polarization |A> = (|H> - |V>)/sqrt(2)"""
        return cls(1, -1)

    @classmethod
    def R(cls):
        """Create right circular polarization |R> = (|H> + i|V>)/sqrt(2)"""
        return cls(1, 1j)

    @classmethod
    def L(cls):
        """Create left circular polarization |L> = (|H> - i|V>)/sqrt(2)"""
        return cls(1, -1j)

    def inner_product(self, other: 'PolarizationQubit') -> complex:
        """Compute <self|other>"""
        return np.vdot(self.state, other.state)

    def overlap_probability(self, other: 'PolarizationQubit') -> float:
        """Compute |<self|other>|^2"""
        return np.abs(self.inner_product(other))**2

    def to_bloch_coordinates(self) -> tuple:
        """
        Convert to Bloch sphere coordinates (theta, phi).
        """
        alpha = self.state[0]
        beta = self.state[1]

        # theta from |alpha|^2 = cos^2(theta/2)
        theta = 2 * np.arccos(np.abs(alpha))

        # phi from relative phase
        if np.abs(beta) > 1e-10:
            # phi = arg(beta) - arg(alpha)
            phi = np.angle(beta) - np.angle(alpha)
        else:
            phi = 0

        return (theta, phi)

    def __repr__(self):
        return f"PolarizationQubit({self.state[0]:.3f}|H> + {self.state[1]:.3f}|V>)"

# Test the implementation
print("Testing polarization states:")
print(f"<H|V> = {PolarizationQubit.H().inner_product(PolarizationQubit.V())}")
print(f"<D|D> = {PolarizationQubit.D().inner_product(PolarizationQubit.D())}")
print(f"|<H|D>|^2 = {PolarizationQubit.H().overlap_probability(PolarizationQubit.D()):.3f}")

theta, phi = PolarizationQubit.D().to_bloch_coordinates()
print(f"D state Bloch coords: theta={theta:.3f} rad, phi={phi:.3f} rad")

# Verify orthogonality
print("\nOrthogonality checks:")
print(f"<H|V> = {PolarizationQubit.H().overlap_probability(PolarizationQubit.V()):.3f}")
print(f"<D|A> = {PolarizationQubit.D().overlap_probability(PolarizationQubit.A()):.3f}")
print(f"<R|L> = {PolarizationQubit.R().overlap_probability(PolarizationQubit.L()):.3f}")
